('afe8638e-b591-5689-a93c-6ecfeda3cc54', 1, 'owner_age_proxy_rpls_tenure', 'positive', NULL, 'Senior RPLS Larry Gus Hada (TBPELS license #2153) granted 1979-12-07 → 47yr tenure. TX RPLS requires 4yr college + 4yr supervised survey-in-training + state exam (typically earned at age 28-35); est. owner age ~77.', 'tbpels_rpls_roster', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/rpls_roster.csv', '2026-05-16'),
('afe8638e-b591-5689-a93c-6ecfeda3cc54', 2, 'firm_tenure_long', 'positive', NULL, 'Senior RPLS Larry Gus Hada tenure 47yr per TBPELS RPLS roster. Firm registered as TBPELS Surveying Firm #10195036 since 2026-05-11. Passes >5yr settled-business hard gate.', 'tbpels_surveying_firms_roster', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/sur-firm_roster.csv', '2026-05-16'),
('afe8638e-b591-5689-a93c-6ecfeda3cc54', 2, 'rpls_license_skilled_trade_moat', 'positive', NULL, 'TX RPLS license = 4yr ABET-accredited surveying or equivalent + 4yr supervised survey-in-training + Tex. Occ. Code Ch. 1071 state exam. ~3,700 active RPLS statewide (TBPELS roster May 2026). Workforce documented as aging (TSPS workforce-shortage reports cite avg RPLS age >55).', 'tbpels_rpls_roster_aggregate', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
('afe8638e-b591-5689-a93c-6ecfeda3cc54', 3, 'solo_rpls_no_successor', 'positive', NULL, 'TBPELS firm roster + RPLS cross-reference shows exactly 1 active RPLS at firm #10195036 (Larry Gus Hada) — no second RPLS added in 47yr tenure. No credentialed internal successor visible at the license-board level. NOTE: live team-page fetch required before A-tier promotion per skill non-negotiable.', 'tbpels_firm_rpls_join', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/rpls_roster.csv', '2026-05-16'),
('afe8638e-b591-5689-a93c-6ecfeda3cc54', 4, 'low_pe_attention_vertical', 'positive', NULL, 'TX land surveying = LOW-PE-ATTENTION vertical. Only Bowman Consulting (NASDAQ:BWMN) + Westwood Professional Services (Endeavour Capital) are PE-backed rollup platforms active in TX surveying. Large-AEC strategics (Stantec/WSP/AECOM/Kimley-Horn/Cobb Fendley/LJA) only bolt-on $5M+ rev firms. Sub-$5M independent universe (Houston, Harris County) structurally under-targeted = opportunity zone. ETA/search-fund appetite emerging fast 2024-2026 per Stanford Search Fund Study (top-15 ETA vertical).', 'verticals.md skill config + Stanford Search Fund Study + Bowman 10-K filings', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
